import { writeOutput } from "./codegen";

const DOCS_URL =
  "https://developer.xero.com/documentation/guides/oauth2/overview/";
const PLACEHOLDER_VALUE =
  "vm0placeholderXeroToken000000000000000000000000000000a";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Xero API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:xero",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const xeroFirewall: FirewallConfig = {",
    '  name: "xero",',
    '  description: "Xero API",',
    "  placeholders: {",
    `    XERO_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.xero.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.XERO_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [",
    "        {",
    '          name: "unrestricted",',
    '          description: "Allow all Xero API endpoints",',
    '          rules: ["ANY /{path*}"],',
    "        },",
    "      ],",
    "    },",
    "  ],",
    "};",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Xero firewall config...");
  const ts = generateTypeScript();
  writeOutput("xero", ts, import.meta.dirname);
}
